tasklist("mealplan", "Creates a weekly meal plan with balanced nutrition, grocery list, and prep schedule", [
  {
    "id": "define-meal-preferences",
    "instructions": "Determine the user's meal planning preferences for the week. Load relevant cuisine and dietary knowledge to understand their restrictions and preferences. Consider: number of people, meals per day, cooking skill level, time available on weekdays vs weekends, budget level, and any nutritional goals (e.g., high protein, low carb, calorie target). Identify which cuisines and techniques the user is comfortable with.",
    "outputSchema": {
      "people": {
        "type": "number",
        "description": "Number of people to feed"
      },
      "mealsPerDay": {
        "type": "number",
        "description": "Number of meals to plan per day"
      },
      "cuisinePreferences": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Preferred cuisine types"
      },
      "dietaryRestrictions": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Active dietary restrictions (e.g., 'vegetarian', 'gluten-free')"
      },
      "weekdayCookingTime": {
        "type": "string",
        "description": "Available cooking time on weekdays (e.g., '30 minutes')"
      },
      "weekendCookingTime": {
        "type": "string",
        "description": "Available cooking time on weekends (e.g., '1-2 hours')"
      },
      "nutritionalGoal": {
        "type": "string",
        "description": "Primary nutrition target (e.g., 'balanced', 'high protein', 'low carb')"
      },
      "calorieTarget": {
        "type": "number",
        "description": "Daily calorie target per person, if specified"
      }
    }
  },
  {
    "id": "design-weekly-menu",
    "instructions": "Design a complete weekly menu based on the user's preferences. Balance variety across cuisines, techniques, and protein sources throughout the week. Assign quicker meals to busy weekdays and more involved recipes to weekends. Plan for leftovers where practical — a weekend roast can become weekday sandwiches or salads. Ensure nutritional balance across the week. Use the estimateCalories function to validate daily calorie totals.",
    "outputSchema": {
      "days": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "day": {
              "type": "string"
            },
            "meals": {
              "type": "array",
              "items": {
                "type": "object",
                "properties": {
                  "mealType": {
                    "type": "string",
                    "description": "breakfast, lunch, dinner, or snack"
                  },
                  "dishName": {
                    "type": "string"
                  },
                  "cuisineType": {
                    "type": "string"
                  },
                  "cookingTime": {
                    "type": "string"
                  },
                  "technique": {
                    "type": "string",
                    "description": "Primary cooking method"
                  },
                  "isLeftover": {
                    "type": "boolean",
                    "description": "Whether this uses leftovers from a previous meal"
                  },
                  "estimatedCalories": {
                    "type": "number"
                  }
                }
              }
            },
            "dailyCalories": {
              "type": "number",
              "description": "Total estimated calories for the day"
            }
          }
        }
      },
      "weeklyStrategy": {
        "type": "string",
        "description": "Overview of the meal plan strategy (variety, leftovers, prep batching)"
      }
    },
    "dependsOn": [
      "define-meal-preferences"
    ]
  },
  {
    "id": "create-prep-schedule",
    "instructions": "Create an efficient prep schedule that batches work to reduce daily effort. Identify ingredients and components that can be prepared in advance — sauces, grains, chopped vegetables, marinated proteins. Organize into a weekend batch-prep session and daily quick-prep tasks. Use the formatTime function to present durations clearly. Include storage instructions and shelf life for prepped items.",
    "outputSchema": {
      "batchPrepSession": {
        "type": "object",
        "properties": {
          "day": {
            "type": "string",
            "description": "When to do batch prep (e.g., 'Sunday afternoon')"
          },
          "totalTime": {
            "type": "string"
          },
          "tasks": {
            "type": "array",
            "items": {
              "type": "object",
              "properties": {
                "task": {
                  "type": "string"
                },
                "usedFor": {
                  "type": "array",
                  "items": {
                    "type": "string"
                  },
                  "description": "Which meals this prep serves"
                },
                "duration": {
                  "type": "string"
                },
                "storage": {
                  "type": "string",
                  "description": "How to store (fridge, freezer, container type)"
                },
                "shelfLife": {
                  "type": "string",
                  "description": "How long the prepped item keeps"
                }
              }
            }
          }
        }
      },
      "dailyPrepTasks": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "day": {
              "type": "string"
            },
            "tasks": {
              "type": "array",
              "items": {
                "type": "string"
              }
            },
            "activeTime": {
              "type": "string",
              "description": "Hands-on time needed"
            }
          }
        }
      }
    },
    "dependsOn": [
      "design-weekly-menu"
    ]
  },
  {
    "id": "build-grocery-list",
    "instructions": "Compile a complete grocery list for the weekly meal plan. Use the buildGroceryList function to deduplicate and consolidate ingredients across all planned meals. Organize items by store section for efficient shopping. Include quantities scaled for the number of people using scaleIngredients. Flag items that may already be in the pantry. Note any specialty items that may require a specific store.",
    "outputSchema": {
      "sections": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "section": {
              "type": "string",
              "description": "Store section (e.g., 'Produce', 'Dairy', 'Meat & Seafood', 'Pantry')"
            },
            "items": {
              "type": "array",
              "items": {
                "type": "object",
                "properties": {
                  "ingredient": {
                    "type": "string"
                  },
                  "quantity": {
                    "type": "string"
                  },
                  "unit": {
                    "type": "string"
                  },
                  "usedIn": {
                    "type": "array",
                    "items": {
                      "type": "string"
                    },
                    "description": "Which meals use this ingredient"
                  },
                  "isSpecialty": {
                    "type": "boolean",
                    "description": "Whether this may need a specialty store"
                  }
                }
              }
            }
          }
        }
      },
      "pantryCheck": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Items likely already in the pantry — verify before buying"
      },
      "estimatedTotal": {
        "type": "string",
        "description": "Rough cost estimate for the grocery list"
      }
    },
    "dependsOn": [
      "create-prep-schedule"
    ]
  }
])

